import com.opengamma.strata.basics.schedule.RollConventions;
import com.opengamma.strata.basics.schedule.Schedule;
import com.opengamma.strata.basics.schedule.SchedulePeriod;
import com.opengamma.strata.basics.schedule.StubConvention;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.product.Product;
import com.opengamma.strata.product.common.BuySell;

/**
 * A synthetic CDO tranche product referencing an underlying CDS index pool.
 * <p>
 * A CDS tranche is a structured credit product that provides protection on a specified
 * portion of losses from a reference portfolio. Losses are absorbed by the tranche only
 * when cumulative portfolio losses exceed the attachment point and up to the detachment point.
 * <p>
 * The protection buyer pays periodic fixed coupons and receives protection payments for
 * losses within the tranche band [attachmentPoint, detachmentPoint].
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * Whether the tranche is buy or sell.
   * <p>
   * A value of 'Buy' implies buying protection, where the fixed coupon is paid
   * and the protection is received for losses within the tranche band.
   * A value of 'Sell' implies selling protection.
   */
  @PropertyDefinition(validate = "notNull")
  private final BuySell buySell;
  /**
   * The CDS index identifier for the underlying reference pool.
   */
  @PropertyDefinition(validate = "notNull")
  private final StandardId cdsIndexId;
  /**
   * The legal entity identifiers of the reference pool constituents.
   */
  @PropertyDefinition(validate = "notNull")
  private final ImmutableList<StandardId> legalEntityIds;
  /**
   * The currency of the tranche notional.
   */
  @PropertyDefinition(validate = "notNull")
  private final Currency currency;
  /**
   * The tranche notional amount, must be positive.
   * <p>
   * Equals (detachmentPoint - attachmentPoint) * poolNotional.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegativeOrZero")
  private final double notional;
  /**
   * The attachment point as a decimal fraction.
   * <p>
   * Losses to the reference pool below this level do not affect this tranche.
   * Must be in the range [0, detachmentPoint).
   */
  @PropertyDefinition
  private final double attachmentPoint;
  /**
   * The detachment point as a decimal fraction.
   * <p>
   * Losses to the reference pool above this level do not affect this tranche.
   * Must be in the range (attachmentPoint, 1].
   */
  @PropertyDefinition
  private final double detachmentPoint;
  /**
   * The payment schedule defining coupon periods.
   */
  @PropertyDefinition(validate = "notNull")
  private final PeriodicSchedule paymentSchedule;
  /**
   * The fixed coupon rate in decimal form.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double fixedRate;
  /**
   * The day count convention.
   * <p>
   * Defaults to 'Act/360'.
   */
  @PropertyDefinition(validate = "notNull")
  private final DayCount dayCount;
  /**
   * The payment on default convention.
   * <p>
   * Defaults to 'AccruedPremium'.
   */
  @PropertyDefinition(validate = "notNull")
  private final PaymentOnDefault paymentOnDefault;
  /**
   * The protection start of day convention.
   * <p>
   * Defaults to 'Beginning'.
   */
  @PropertyDefinition(validate = "notNull")
  private final ProtectionStartOfDay protectionStart;
  /**
   * The number of days between valuation date and step-in date.
   * <p>
   * Defaults to 1 calendar day.
   */
  @PropertyDefinition(validate = "notNull")
  private final DaysAdjustment stepinDateOffset;
  /**
   * The number of days between valuation date and settlement date.
   * <p>
   * Defaults to 3 business days in the payment schedule calendar.
   */
  @PropertyDefinition(validate = "notNull")
  private final DaysAdjustment settlementDateOffset;

  //-------------------------------------------------------------------------
  /**
   * Creates a standardized CDS tranche.
   *
   * @param buySell  buy or sell
   * @param cdsIndexId  the underlying CDS index ID
   * @param legalEntityIds  the reference entity IDs
   * @param currency  the currency
   * @param notional  the tranche notional
   * @param attachmentPoint  the attachment point as a decimal fraction
   * @param detachmentPoint  the detachment point as a decimal fraction
   * @param startDate  the protection start date
   * @param endDate  the protection end date
   * @param paymentFrequency  the coupon payment frequency
   * @param calendar  the holiday calendar
   * @param fixedRate  the fixed coupon rate as a decimal fraction
   * @return the CDS tranche instance
   */
  public static CdsTranche of(
      BuySell buySell,
      StandardId cdsIndexId,
      List<StandardId> legalEntityIds,
      Currency currency,
      double notional,
      double attachmentPoint,
      double detachmentPoint,
      LocalDate startDate,
      LocalDate endDate,
      Frequency paymentFrequency,
      HolidayCalendarId calendar,
      double fixedRate) {

    PeriodicSchedule accrualSchedule = PeriodicSchedule.builder()
        .businessDayAdjustment(BusinessDayAdjustment.of(BusinessDayConventions.FOLLOWING, calendar))
        .startDate(startDate)
        .endDate(endDate)
        .startDateBusinessDayAdjustment(BusinessDayAdjustment.NONE)
        .endDateBusinessDayAdjustment(BusinessDayAdjustment.NONE)
        .frequency(paymentFrequency)
        .rollConvention(RollConventions.NONE)
        .stubConvention(StubConvention.SMART_INITIAL)
        .build();
    return new CdsTranche(
        buySell,
        cdsIndexId,
        legalEntityIds,
        currency,
        notional,
        attachmentPoint,
        detachmentPoint,
        accrualSchedule,
        fixedRate,
        DayCounts.ACT_360,
        PaymentOnDefault.ACCRUED_PREMIUM,
        ProtectionStartOfDay.BEGINNING,
        DaysAdjustment.ofCalendarDays(1),
        DaysAdjustment.ofBusinessDays(3, calendar));
  }

  @ImmutableDefaults
  private static void applyDefaults(Builder builder) {
    builder.dayCount = DayCounts.ACT_360;
    builder.paymentOnDefault = PaymentOnDefault.ACCRUED_PREMIUM;
    builder.protectionStart = ProtectionStartOfDay.BEGINNING;
    builder.stepinDateOffset = DaysAdjustment.ofCalendarDays(1);
  }

  @ImmutablePreBuild
  private static void preBuild(Builder builder) {
    if (builder.settlementDateOffset == null && builder.paymentSchedule != null) {
      builder.settlementDateOffset =
          DaysAdjustment.ofBusinessDays(3, builder.paymentSchedule.getBusinessDayAdjustment().getCalendar());
    }
  }

  //-------------------------------------------------------------------------
  @Override
  public ImmutableSet<Currency> allCurrencies() {
    return ImmutableSet.of(currency);
  }

  @Override
  public ResolvedCdsTranche resolve(ReferenceData refData) {
    Schedule adjustedSchedule = paymentSchedule.createSchedule(refData);
    ImmutableList.Builder<CreditCouponPaymentPeriod> accrualPeriods = ImmutableList.builder();
    int nPeriods = adjustedSchedule.size();
    for (int i = 0; i < nPeriods - 1; i++) {
      SchedulePeriod period = adjustedSchedule.getPeriod(i);
      accrualPeriods.add(CreditCouponPaymentPeriod.builder()
          .startDate(period.getStartDate())
          .endDate(period.getEndDate())
          .unadjustedStartDate(period.getUnadjustedStartDate())
          .unadjustedEndDate(period.getUnadjustedEndDate())
          .effectiveStartDate(protectionStart.isBeginning() ? period.getStartDate().minusDays(1) : period.getStartDate())
          .effectiveEndDate(protectionStart.isBeginning() ? period.getEndDate().minusDays(1) : period.getEndDate())
          .paymentDate(period.getEndDate())
          .notional(notional)
          .currency(currency)
          .fixedRate(fixedRate)
          .yearFraction(period.yearFraction(dayCount, adjustedSchedule))
          .build());
    }
    SchedulePeriod lastPeriod = adjustedSchedule.getPeriod(nPeriods - 1);
    LocalDate accEndDate = protectionStart.isBeginning() ? lastPeriod.getEndDate().plusDays(1) : lastPeriod.getEndDate();
    SchedulePeriod modifiedPeriod = lastPeriod.toBuilder().endDate(accEndDate).build();
    accrualPeriods.add(CreditCouponPaymentPeriod.builder()
        .startDate(modifiedPeriod.getStartDate())
        .endDate(modifiedPeriod.getEndDate())
        .unadjustedStartDate(modifiedPeriod.getUnadjustedStartDate())
        .unadjustedEndDate(modifiedPeriod.getUnadjustedEndDate())
        .effectiveStartDate(protectionStart.isBeginning() ? lastPeriod.getStartDate().minusDays(1) : lastPeriod.getStartDate())
        .effectiveEndDate(lastPeriod.getEndDate())
        .paymentDate(paymentSchedule.getBusinessDayAdjustment().adjust(lastPeriod.getEndDate(), refData))
        .notional(notional)
        .currency(currency)
        .fixedRate(fixedRate)
        .yearFraction(modifiedPeriod.yearFraction(dayCount, adjustedSchedule))
        .build());

    return ResolvedCdsTranche.builder()
        .buySell(buySell)
        .cdsIndexId(cdsIndexId)
        .legalEntityIds(legalEntityIds)
        .attachmentPoint(attachmentPoint)
        .detachmentPoint(detachmentPoint)
        .protectionStart(protectionStart)
        .paymentOnDefault(paymentOnDefault)
        .paymentPeriods(accrualPeriods.build())
        .protectionEndDate(lastPeriod.getEndDate())
        .settlementDateOffset(settlementDateOffset)
        .stepinDateOffset(stepinDateOffset)
        .dayCount(dayCount)
        .build();
  }

