    21   * At present, this integrator can only be used for the limits $\pm\infty$. The
    22   * function to integrate is scaled in such a way as to allow any values for the
    23   * limits of integration.
    24   */
    25  public class GaussHermiteQuadratureIntegrator1D extends GaussianQuadratureIntegrator1D {
    26
    27    private static final Double[] LIMITS = new Double[] {Double.NEGATIVE_INFINITY, Double.POSITIVE_INFINITY};
    28    private static final GaussHermiteWeightAndAbscissaFunction GENERATOR = new GaussHermiteWeightAndAbscissaFunction();
    29
    30    /**
    31     * @param n The number of sample points to use in the integration
    32     */
    33    public GaussHermiteQuadratureIntegrator1D(int n) {
    34      super(n, GENERATOR);
    35    }
    36
    37    /**
    38     * {@inheritDoc}
    39     */
    40    @Override
    41    public Double[] getLimits() {
    42      return LIMITS;
    43    }
    44
    45    /**
    46     * {@inheritDoc}
    47     * The function $f(x)$ that is to be integrated is transformed into a form
    48     * suitable for this quadrature method using:
    49     * $$
    50     * \begin{align*}
    51     * \int_{-\infty}^{\infty} f(x) dx
    52     * &= \int_{-\infty}^{\infty} f(x) e^{x^2} e^{-x^2} dx\\
    53     * &= \int_{-\infty}^{\infty} g(x) e^{-x^2} dx
    54     * \end{align*}
    55     * $$
    56     * @throws UnsupportedOperationException If the lower limit is not $-\infty$ or the upper limit is not $\infty$
    57     */
    58    @Override
    59    public Function<Double, Double> getIntegralFunction(Function<Double, Double> function, Double lower, Double upper) {
    60      ArgChecker.notNull(function, "function");
    61      ArgChecker.notNull(lower, "lower");
    62      ArgChecker.notNull(upper, "upper");
    63      if (lower.equals(LIMITS[0]) && upper.equals(LIMITS[1])) {
    64        return new Function<Double, Double>() {
    65          @Override
    66          public Double apply(Double x) {
    67            return Math.exp(x * x) * function.apply(x);
    68          }
    69        };
    70      }
    71      throw new UnsupportedOperationException("Limits for this integration method are +/-infinity");
    72    }
    73
    74  }

