package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;
import java.util.function.Function;

import com.opengamma.strata.basics.StandardId;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.math.impl.integration.GaussHermiteQuadratureIntegrator1D;
import com.opengamma.strata.math.impl.statistics.distribution.NormalDistribution;
import com.opengamma.strata.product.credit.CreditCouponPaymentPeriod;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Pricer for synthetic CDO tranches based on the ISDA Large Homogeneous Pool (LHP) Gaussian copula model.
 * <p>
 * The model assumes a one-factor Gaussian copula with a single correlation parameter (rho) applied
 * uniformly across all reference names.  Survival probabilities for each name are taken from a
 * single representative credit curve identified by the tranche's {@code cdsIndexId}.
 * <p>
 * The pricing equations are:
 * <pre>
 *   q(z, t)      = N( (N⁻¹(p(t)) − √ρ·z) / √(1−ρ) )     conditional default probability
 *   ETL(t)       = ∫ max(min(q(z,t)·LGD, D) − A, 0) · φ(z) dz
 *   premiumPV    = fixedRate · notional · Σᵢ df(tᵢ) · τᵢ · (1 − avgETL(tᵢ))
 *   protectionPV = notional · Σᵢ df(tᵢ) · ΔnETL(tᵢ)
 *   PV(buyer)    = protectionPV − premiumPV
 * </pre>
 * where {@code A} is the attachment point, {@code D} is the detachment point, {@code LGD = 1 − recovery},
 * {@code p(t) = 1 − Q(t)} is the unconditional default probability, and {@code φ} is the standard
 * normal density.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT = new IsdaCdsTranchePricer();

  private static final NormalDistribution NORMAL = new NormalDistribution(0d, 1d);
  private static final double INV_SQRT_2PI = 1d / Math.sqrt(2d * Math.PI);
  // 32-point Gauss–Hermite quadrature integrates ∫e^{-x²}g(x)dx; we wrap the φ(z) density.
  private static final GaussHermiteQuadratureIntegrator1D INTEGRATOR =
      new GaussHermiteQuadratureIntegrator1D(32);

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the tranche from the buyer's perspective.
   * <p>
   * PV = protection leg PV − premium leg PV.
   *
   * @param tranche  the resolved tranche product
   * @param ratesProvider  the credit rates provider
   * @return the present value
   */
  public CurrencyAmount presentValue(ResolvedCdsTranche tranche, CreditRatesProvider ratesProvider) {
    Currency currency = tranche.getCurrency();
    double notional = tranche.getNotional();
    double pv = calcPv(tranche, ratesProvider);
    return CurrencyAmount.of(currency, tranche.getBuySell().normalize(notional) * pv);
  }

  /**
   * Calculates the present value of the protection leg (credit leg).
   *
   * @param tranche  the resolved tranche product
   * @param ratesProvider  the credit rates provider
   * @return the protection leg present value
   */
  public CurrencyAmount protectionLegPresentValue(ResolvedCdsTranche tranche, CreditRatesProvider ratesProvider) {
    double notional = tranche.getNotional();
    double pv = calcProtectionLegPv(tranche, ratesProvider);
    return CurrencyAmount.of(tranche.getCurrency(), notional * pv);
  }

  /**
   * Calculates the present value of the premium leg (fee leg).
   *
   * @param tranche  the resolved tranche product
   * @param ratesProvider  the credit rates provider
   * @return the premium leg present value
   */
  public CurrencyAmount premiumLegPresentValue(ResolvedCdsTranche tranche, CreditRatesProvider ratesProvider) {
    double notional = tranche.getNotional();
    double pv = calcPremiumLegPv(tranche, ratesProvider);
    return CurrencyAmount.of(tranche.getCurrency(), notional * pv);
  }

  /**
   * Calculates the present value of the trade, including any upfront payment.
   *
   * @param trade  the resolved tranche trade
   * @param ratesProvider  the credit rates provider
   * @return the trade present value
   */
  public CurrencyAmount presentValue(ResolvedCdsTrancheTrade trade, CreditRatesProvider ratesProvider) {
    return presentValue(trade.getProduct(), ratesProvider);
  }

  //-------------------------------------------------------------------------
  // Core PV calculation: protectionLeg - premiumLeg (normalised, without notional sign)
  private double calcPv(ResolvedCdsTranche tranche, CreditRatesProvider ratesProvider) {
    return calcProtectionLegPv(tranche, ratesProvider) - calcPremiumLegPv(tranche, ratesProvider);
  }

  private double calcProtectionLegPv(ResolvedCdsTranche tranche, CreditRatesProvider ratesProvider) {
    StandardId legalEntityId = tranche.getCdsIndexId();
    Currency currency = tranche.getCurrency();
    double A = tranche.getAttachmentPoint();
    double D = tranche.getDetachmentPoint();
    double width = D - A;
    ArgChecker.isTrue(width > 0d, "detachmentPoint must exceed attachmentPoint");
    double rho = tranche.getCorrelationFactor();

    CreditDiscountFactors discountFactors = ratesProvider.discountFactors(currency);
    LegalEntitySurvivalProbabilities survivalProbs = ratesProvider.survivalProbabilities(legalEntityId, currency);
    RecoveryRates recoveryRates = ratesProvider.recoveryRates(legalEntityId);

    double protectionLeg = 0d;
    double prevNetl = normalizedEtl(tranche.getStartDate(), survivalProbs, recoveryRates, A, D, rho);
    for (CreditCouponPaymentPeriod period : tranche.getPaymentPeriods()) {
      LocalDate payDate = period.getPaymentDate();
      double df = discountFactors.discountFactor(payDate);
      double netl = normalizedEtl(period.getEndDate(), survivalProbs, recoveryRates, A, D, rho);
      protectionLeg += df * (netl - prevNetl);
      prevNetl = netl;
    }
    return protectionLeg;
  }

  private double calcPremiumLegPv(ResolvedCdsTranche tranche, CreditRatesProvider ratesProvider) {
    StandardId legalEntityId = tranche.getCdsIndexId();
    Currency currency = tranche.getCurrency();
    double A = tranche.getAttachmentPoint();
    double D = tranche.getDetachmentPoint();
    double rho = tranche.getCorrelationFactor();
    double fixedRate = tranche.getFixedRate();

    CreditDiscountFactors discountFactors = ratesProvider.discountFactors(currency);
    LegalEntitySurvivalProbabilities survivalProbs = ratesProvider.survivalProbabilities(legalEntityId, currency);
    RecoveryRates recoveryRates = ratesProvider.recoveryRates(legalEntityId);

    double premiumLeg = 0d;
    double prevNetl = normalizedEtl(tranche.getStartDate(), survivalProbs, recoveryRates, A, D, rho);
    for (CreditCouponPaymentPeriod period : tranche.getPaymentPeriods()) {
      LocalDate payDate = period.getPaymentDate();
      double df = discountFactors.discountFactor(payDate);
      double tau = period.getYearFraction();
      double netl = normalizedEtl(period.getEndDate(), survivalProbs, recoveryRates, A, D, rho);
      double avgNetl = 0.5d * (prevNetl + netl);
      premiumLeg += df * tau * (1d - avgNetl);
      prevNetl = netl;
    }
    return fixedRate * premiumLeg;
  }

  //-------------------------------------------------------------------------
  /**
   * Computes the normalised expected tranche loss (ETL) at a given date.
   * <p>
   * normalizedETL = ETL(t) / (D − A), where
   * ETL(t) = ∫ max(min(q(z,t)·LGD, D) − A, 0) · φ(z) dz
   */
  double normalizedEtl(
      LocalDate date,
      LegalEntitySurvivalProbabilities survivalProbs,
      RecoveryRates recoveryRates,
      double A,
      double D,
      double rho) {

    double width = D - A;
    double survProb = survivalProbs.survivalProbability(date);
    double p = 1d - survProb;  // unconditional default probability at time t

    // recovery rate evaluated at the protection end date; use date as proxy
    double recovery = recoveryRates.recoveryRate(date);
    double lgd = 1d - recovery;

    if (p <= 0d || lgd <= 0d) {
      return 0d;
    }
    if (p >= 1d) {
      // fully defaulted pool: ETL = max(min(lgd, D) - A, 0) / width
      double trancheLoss = Math.max(Math.min(lgd, D) - A, 0d);
      return trancheLoss / width;
    }

    double invNormP = NORMAL.getInverseCDF(p);
    double sqrtRho = Math.sqrt(rho);
    double sqrtOneMinusRho = Math.sqrt(1d - rho);

    // ETL(t) = ∫ max(min(q(z,t)*lgd, D) - A, 0) * φ(z) dz
    // Gauss–Hermite computes ∫ e^{-x²} g(x) dx; we use the transform x = z/√2,
    // so φ(z) dz = (1/√2π) e^{-z²/2} dz, and with x=z/√2:
    //   φ(z) dz = (1/√2π) e^{-x²} √2 dx = (√2/√2π) e^{-x²} dx = (1/√π) e^{-x²} dx
    // Therefore: integrate(f, -∞, +∞) computes ∫ e^{x²} f(x) · e^{-x²} dx
    // We supply f(x) = integrand(√2·x) / √π so that the result equals ETL.

    final double invNormP_f = invNormP;
    final double lgd_f = lgd;

    Function<Double, Double> integrandGH = (Double x) -> {
      double z = Math.sqrt(2d) * x;
      double arg = (invNormP_f - sqrtRho * z) / sqrtOneMinusRho;
      double qz = NORMAL.getCDF(arg);
      double poolLoss = qz * lgd_f;
      double trancheLoss = Math.max(Math.min(poolLoss, D) - A, 0d);
      // divide by sqrt(pi) to convert e^{-x²} weight to standard normal density
      return trancheLoss / Math.sqrt(Math.PI);
    };

    double etl = INTEGRATOR.integrate(integrandGH, Double.NEGATIVE_INFINITY, Double.POSITIVE_INFINITY);
    return etl / width;
  }
}

