package com.opengamma.strata.measure.credit;

import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.data.scenario.CurrencyScenarioArray;
import com.opengamma.strata.pricer.credit.CreditRatesProvider;
import com.opengamma.strata.pricer.credit.IsdaCdsTranchePricer;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Multi-scenario measure calculations for CDS tranche trades.
 * <p>
 * Each method corresponds to a measure, calculated by delegating to {@link IsdaCdsTranchePricer}.
 */
final class CdsTrancheMeasureCalculations {

  /**
   * Default implementation.
   */
  static final CdsTrancheMeasureCalculations DEFAULT =
      new CdsTrancheMeasureCalculations(IsdaCdsTranchePricer.DEFAULT);

  /**
   * The pricer for {@link ResolvedCdsTrancheTrade}.
   */
  private final IsdaCdsTranchePricer tradePricer;

  //-------------------------------------------------------------------------
  /**
   * Creates an instance.
   *
   * @param tradePricer  the pricer for {@link ResolvedCdsTrancheTrade}
   */
  CdsTrancheMeasureCalculations(IsdaCdsTranchePricer tradePricer) {
    this.tradePricer = ArgChecker.notNull(tradePricer, "tradePricer");
  }

  //-------------------------------------------------------------------------
  // calculates present value for all scenarios
  CurrencyScenarioArray presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> presentValue(trade, marketData.scenario(i).creditRatesProvider()));
  }

  // calculates present value for one scenario
  CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider) {

    return tradePricer.presentValue(trade, ratesProvider);
  }

  //-------------------------------------------------------------------------
  // calculates protection leg PV for all scenarios
  CurrencyScenarioArray protectionLegPresentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> protectionLegPresentValue(trade, marketData.scenario(i).creditRatesProvider()));
  }

  // calculates protection leg PV for one scenario
  CurrencyAmount protectionLegPresentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider) {

    return tradePricer.protectionLegPresentValue(trade.getProduct(), ratesProvider);
  }

  //-------------------------------------------------------------------------
  // calculates premium leg PV for all scenarios
  CurrencyScenarioArray premiumLegPresentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> premiumLegPresentValue(trade, marketData.scenario(i).creditRatesProvider()));
  }

  // calculates premium leg PV for one scenario
  CurrencyAmount premiumLegPresentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider) {

    return tradePricer.premiumLegPresentValue(trade.getProduct(), ratesProvider);
  }
}

